func generateCombinations(chars []rune, prefix string, length int, words *[]string) {
	if length == 0 {
		*words = append(*words, prefix+"1")
		//return
	}

	for _, char := range chars {
		generateCombinations(chars, prefix+string(char), length-1, words)
	}
}

type Test struct {
	Active int
	Root   int
}

func createString() {
	rand.Seed(time.Now().UnixNano())
	length := 2000
	chars := []rune{'A', 'C', 'T', 'G'}
	randomString := make([]rune, length)

	for i := range randomString {
		randomString[i] = chars[rand.Intn(len(chars))]
	}

	fmt.Println(string(randomString))
}

